	result := new(*IWebAccountProviderCommand)
	r1, _, _ := syscall.SyscallN(self.LpVtbl[6], uintptr(unsafe.Pointer(self)), uintptr(unsafe.Pointer(webAccountProvider)), _invoked, uintptr(winrt.OutParam(unsafe.Pointer(result))))
